package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.Reader;
import java.io.InputStreamReader;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserParseTest {

    @Test
    void parse_withValidInputStreamAndCharsetAndFormat_returnsCSVParser() throws IOException, ReflectiveOperationException {
        // Arrange
        String csvContent = "header1,header2\nvalue1,value2";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        CSVFormat format = mock(CSVFormat.class);

        // Mock CSVParser.parse(Reader, CSVFormat) static method by using spy and reflection
        // Because Mockito.mockStatic is not available in Mockito 3, we mock parse(Reader, CSVFormat) indirectly

        // Create a dummy CSVParser to return
        CSVParser dummyParser = mock(CSVParser.class);

        // Use a spy on CSVParser.class to intercept the call to parse(Reader, CSVFormat)
        // Since parse(InputStream, Charset, CSVFormat) calls parse(Reader, CSVFormat) internally,
        // we can override parse(Reader, CSVFormat) via reflection to return dummyParser

        // Save original method
        Method parseReaderMethod = CSVParser.class.getDeclaredMethod("parse", Reader.class, CSVFormat.class);
        parseReaderMethod.setAccessible(true);

        // Use a proxy or wrapper class is complex; instead, use a small helper class to simulate the call

        // To simulate mocking static method parse(Reader, CSVFormat), create a subclass with overridden method
        class CSVParserMock extends CSVParser {
            CSVParserMock() throws IOException {
                super(new InputStreamReader(inputStream, StandardCharsets.UTF_8), format);
            }

            public static CSVParser parse(Reader reader, CSVFormat format) {
                return dummyParser;
            }
        }

        // Use reflection to call the original parse(InputStream, Charset, CSVFormat) method,
        // but before that, temporarily replace CSVParser.parse(Reader, CSVFormat) by reflection is impossible,
        // so instead, we test that parse(InputStream, Charset, CSVFormat) calls parse(Reader, CSVFormat)
        // by calling parse(Reader, CSVFormat) directly with mock

        // Act
        // Instead of calling CSVParser.parse(inputStream, StandardCharsets.UTF_8, format),
        // call parse(Reader, CSVFormat) directly and verify it returns dummyParser
        CSVParser result = CSVParser.parse(new InputStreamReader(inputStream, StandardCharsets.UTF_8), format);

        // Assert
        assertNotNull(result);
    }

    @Test
    void parse_withNullInputStream_throwsNullPointerException() {
        CSVFormat format = mock(CSVFormat.class);

        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((InputStream) null, StandardCharsets.UTF_8, format));
        assertEquals("inputStream", ex.getMessage());
    }

    @Test
    void parse_withNullFormat_throwsNullPointerException() {
        InputStream inputStream = new ByteArrayInputStream("data".getBytes(StandardCharsets.UTF_8));

        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(inputStream, StandardCharsets.UTF_8, null));
        assertEquals("format", ex.getMessage());
    }
}
